import{_ as e,o as r,c as i,a3 as n}from"./chunks/framework.oxq6d-og.js";const h=JSON.parse('{"title":"Accessor zinciri","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/accessors.md","filePath":"architecture/accessors.md"}'),s={name:"architecture/accessors.md"};function c(t,a,l,o,d,m){return r(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="accessor-zinciri" tabindex="-1">Accessor zinciri <a class="header-anchor" href="#accessor-zinciri" aria-label="Permalink to &quot;Accessor zinciri&quot;">​</a></h1><p>Accessor, Exoproc&#39;un en önemli soyutlamalarından biridir. Aynı işlem kümesi — <code>read</code>, <code>write</code>, <code>alloc</code>, <code>free</code>, <code>protect</code>, <code>scan</code> ve <code>call</code> — farklı bellek erişim biçimleri için ortak bir arayüzde sunulur.</p><h2 id="neyi-cozer" tabindex="-1">Neyi çözer? <a class="header-anchor" href="#neyi-cozer" aria-label="Permalink to &quot;Neyi çözer?&quot;">​</a></h2><p>Bir <code>struct</code> alanı için “bu değer yerel bellekteyse senkron, uzaktaysa asenkron API kullan” ayrımı üst katmana sızarsa, her özellik taşıma mekanizmasına bağımlı olur. Accessor, bu ayrımı taşır: struct yerleşimini bilir; verinin nereden geldiğini accessor bilir.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Struct / CFunction</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>IMemoryAccessor</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>Middleware&#39;ler</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>Yerel API | Remote API | NThread yönlendirmesi</span></span></code></pre></div><h2 id="indirectnthreadhostaccessor" tabindex="-1">IndirectNThreadHostAccessor <a class="header-anchor" href="#indirectnthreadhostaccessor" aria-label="Permalink to &quot;IndirectNThreadHostAccessor&quot;">​</a></h2><p><code>IndirectNThreadHostAccessor</code>, çağrı çalıştırıcısı olarak NThread&#39;i kullanır ve bunun üzerine middleware&#39;ler ekler. Zincirde çağrı yönlendirme, machine-code havuzu, <code>memset</code> tabanlı yazma, <code>memcmp</code> tabanlı okuma, dosya aktarımı, tarama ve ABI marshalling bulunur.</p><p>Bu kurulumda yalnızca <code>call()</code> değil, allocation, okuma ve yazma gibi işlemler de aynı erişim stratejisi içinde kalabilir. Karşılığı; hata ayıklamada tek bir “uzak bellek işlemi”nin birden fazla middleware&#39;den geçtiğinin bilinmesidir.</p><h2 id="baslatma-sırası" tabindex="-1">Başlatma sırası <a class="header-anchor" href="#baslatma-sırası" aria-label="Permalink to &quot;Başlatma sırası&quot;">​</a></h2><p>Accessor zinciri yaşam döngüsü taşır. <code>IndirectNThreadHostAccessor</code> başlatıldığında bootstrap root ve alt zincir hazırlanır; NThread ise gerekli stub taramasını bekleyip thread&#39;i park eder. <code>createAccessor()</code> bu <code>init()</code> akışını bekleyerek döner. Sınıfı doğrudan kuruyorsanız <code>await init()</code> tamamlanmadan kullanmayın; genel accessor üzerinde olmayan bir <code>whenReady()</code> çağrısını varsaymayın.</p><p>Bir hata görüldüğünde önce hangi katmanın çağrıyı gerçekten yürüttüğünü belirleyin. <code>NThread</code> kaynaklı timeout ile middleware&#39;in yanlış marshal ettiği imza aynı belirtiyi üretebilir, fakat çözüm yerleri farklıdır. Varsayılan zincirin seçim ve cleanup davranışı için <a href="/exoproc/previews/feature-docs/packages/nthread">NThread accessor rehberine</a> bakın.</p>`,11)])])}const u=e(s,[["render",c]]);export{h as __pageData,u as default};
